  1012→	}
  1013→	keyMap := map[string]struct{}{}
  1014→	keyToNodeMap := map[string]ast.Node{}
  1015→	if mapNode == nil {
  1016→		return keyToNodeMap, nil
  1017→	}
  1018→	mapIter := mapNode.MapRange()
  1019→	for mapIter.Next() {
  1020→		keyNode := mapIter.Key()
