  1037→			if !ok {
  1038→				return nil, errors.Wrapf(err, "failed to decode map key")
  1039→			}
  1040→			if err := d.validateDuplicateKey(keyMap, key, keyNode); err != nil {
  1041→				return nil, errors.Wrapf(err, "invalid struct key")
  1042→			}
  1043→			keyToNodeMap[key] = getKeyOrValueNode(mapIter)
  1044→		}
  1045→	}
  1046→	return keyToNodeMap, nil
